import{_ as i,o as t,c as r,a4 as a}from"./chunks/framework.DkKDtR5x.js";const p=JSON.parse('{"title":"Spring Security","description":"","frontmatter":{},"headers":[],"relativePath":"backend/spring/security.md","filePath":"backend/spring/security.md"}'),n={name:"backend/spring/security.md"};function l(o,e,s,c,u,h){return t(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="spring-security" tabindex="-1">Spring Security <a class="header-anchor" href="#spring-security" aria-label="Permalink to “Spring Security”">​</a></h1><p>Framework that focuses on providing both authentication and authorization to Java applications.</p><p>Official site <a href="https://spring.io/projects/spring-security" target="_blank">spring-security</a></p><h1 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to “References”">​</a></h1><ul><li>Youtube <ul><li><a href="https://www.youtube.com/live/GdgzXLAbnn8?si=wo2Hidhq2pwWYh4Z" target="_blank">Spring Office Hours: S3E17 - Spring Security Architecture Principals</a></li></ul></li></ul><h1 id="pretext" tabindex="-1">Pretext <a class="header-anchor" href="#pretext" aria-label="Permalink to “Pretext”">​</a></h1><ul><li>Servlet Applications : <ul><li>Servlets are Java classes that extend the capabilities of web servers by handling client requests and generating dynamic content.</li><li>They can read HTTP headers, write HTML responses, process user input, and interact with databases or other backend systems.</li><li>Servlets are typically deployed as part of a web application, often packaged in a WAR (Web Application Archive) file.</li></ul></li><li>Web Applications : <ul><li>Broader concept encompassing all the components needed to deliver a web-based service to users.</li><li>They include servlets, JSPs (JavaServer Pages), HTML, CSS, JavaScript, images, and other resources that work together to deliver a specific functionality.</li></ul></li></ul><p><strong>Why Spring Security?</strong></p><ul><li>Securing endpoints</li><li>Need to interact with http traffic</li></ul><h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to “Introduction”">​</a></h1><ul><li>In spring MVC, we interact with Http traffic using an interface called servlet filter (jakarta package).</li><li>It has one method taking params - Request object, Response object and FilterChain <ul><li>This reads the request, make security decision and write to response.</li><li>Like add context, block response OR do nothing and delegate to other filters in the filter chain and eventually request reaches the controller method.</li><li>This is the Core of onteracting with Http, the entry point for all the things.</li></ul></li><li>At low level, you need to understand <ul><li>where is the security stuff in the Http request.</li><li>How to parse a MTLS or TLS certificate</li></ul></li><li><code>Authentication</code> interface in spring security represents the logged-in entity OR entity making the request to application.</li><li>Entity can be <ul><li>logged-in user</li><li>session cookie</li><li>automated robot account</li><li>token</li></ul></li><li>Spring security has a way in the filters that takes the low level details (implementation details) and transforms it into an authentication object representing the Authentication request.</li><li>Spring security has an Authentication Manager which has list of Authentication Providers.</li><li>As a user, you implement authentication provideers that take authentication request and turn them to successful Authentications.</li><li>Common usecase - Form login when you start with spring security</li><li>As a user, we need to know how to validate the Auth request into something that works.</li></ul><h1 id="principal-vs-userdetails" tabindex="-1">Principal vs UserDetails <a class="header-anchor" href="#principal-vs-userdetails" aria-label="Permalink to “Principal vs UserDetails”">​</a></h1><ul><li><code>Authentication</code> extends Principal (java security package)</li><li>Never ever touch the low level Java Principal, better to work with Authentication.</li><li>Authentication <ul><li>getPrincipal identifies WHO?</li><li>getGrantedAuthorities identifies if Authorized?</li></ul></li><li>Example of Principal <ul><li>For username/password login - Principal is loaded as UserDetails from DB.</li><li>OAuth login - Principal will be OAuth User</li></ul></li><li>UserDetails is one of the implementations used for Principal</li></ul><h1 id="securitycontext-and-securitycontextholder" tabindex="-1">SecurityContext and SecurityContextHolder <a class="header-anchor" href="#securitycontext-and-securitycontextholder" aria-label="Permalink to “SecurityContext and SecurityContextHolder”">​</a></h1><ul><li>SecurityContext in spring security is the thread local per request object made and Authentication is put into it.</li><li>Anywhere in our dependency tree, we can call <code>SecurityContextHolder.getContext().getAuthentication()</code> so you don&#39;t&#39; have to pass it down.</li><li>DEBUGGING TIP <ul><li>You can check the log statement from Default security filter chain class <code>We&#39;ll secure such path ...</code> and see the list of filters loaded for the application.</li><li>If somthing explodes and you need to find where the bug is present in the security filter chain or where its stuck in securoty chain, Then to debug set the spring security log level to TRACE <code>logging.level.org.springframework.security=TRACE</code> and debug the last invoked filter in the logs</li></ul></li><li>spring.io does have good diagrams, example - <a href="https://docs.spring.io/spring-security/reference/servlet/architecture.html#servlet-securityfilterchain" target="_blank">SecurityFilterChain</a> and <a href="https://docs.spring.io/spring-security/reference/servlet/authentication/architecture.html#servlet-authentication-securitycontextholder" target="_blank">SecurityContextHolder</a></li><li>Other Refs <ul><li>ACL - Access Control List</li><li>Dynamic role access for menu management</li><li>LDAP</li><li><a href="https://2024.springio.net/sessions/spring-security-architecture-principles/" target="_blank">Spring Security Architecture Principles - by Daniel Garnier-Moiroux - Broadcom</a> - presentation pdf <a href="https://2024.springio.net/slides/spring-security-architecture-principles-springio24.pdf" target="_blank">here</a></li><li>practice to be good at live coding : shift shift zoom</li></ul></li></ul><h1 id="annotations" tabindex="-1">Annotations <a class="header-anchor" href="#annotations" aria-label="Permalink to “Annotations”">​</a></h1><ul><li><code>@PreAuthorize</code></li><li><code>@PostAuthorize</code></li></ul><p>OAuth2</p><ul><li>Components and dependency <ul><li>Resource Server : <code>spring-security</code></li><li>Client : <code>spring-security</code></li><li>Authorization Server : <code>spring-authorization-server</code></li></ul></li><li>Token Exchange Grant <ul><li>token with read write</li><li>exchange to get token only with read</li></ul></li></ul><p>CORS and CSRF with spring security</p><ul><li>enable CORS in spring backend</li><li>CSRF default on</li></ul>',21)])])}const g=i(n,[["render",l]]);export{p as __pageData,g as default};
